// Extraer datos del body
const body = $input.first().json.body || $input.first().json;

const companySlug = body.company_slug || 'default';
const filename = body.filename || 'document.pdf';
const category = body.category || 'general';
const fileBase64 = body.file || '';
const mimeType = body.mime_type || 'application/pdf';

// Limpiar el base64 (quitar data:... prefix si existe)
let cleanBase64 = fileBase64;
if (cleanBase64.includes(',')) {
  cleanBase64 = cleanBase64.split(',')[1];
}

// Crear nombre de colección
const collectionName = 'company_' + companySlug.replace(/[^a-z0-9_-]/gi, '_').toLowerCase() + '_knowledge';

// Preparar como binary data para el nodo Extract From File
return {
  json: {
    company_slug: companySlug,
    filename: filename,
    category: category,
    collection_name: collectionName,
    mime_type: mimeType
  },
  binary: {
    data: {
      data: cleanBase64,
      mimeType: mimeType,
      fileName: filename
    }
  }
};

// Combinar el texto extraído con los metadatos originales
const extractedData = $input.first().json;
const prevData = $('Prepare Binary Data').first().json;

// El texto extraído viene en el campo 'text' del nodo Extract From File
const extractedText = extractedData.text || extractedData.data || '';

// Limpiar el texto: remover caracteres no imprimibles y normalizar espacios
let cleanText = extractedText
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]/g, '') // Remover caracteres de control
  .replace(/\s+/g, ' ') // Normalizar espacios múltiples
  .replace(/\n\s*\n/g, '\n\n') // Mantener párrafos
  .trim();

// Verificar que tenemos texto válido
if (!cleanText || cleanText.length < 10) {
  throw new Error('No se pudo extraer texto del documento. El archivo puede estar vacío, ser una imagen escaneada, o estar protegido.');
}

return {
  json: {
    company_slug: prevData.company_slug,
    filename: prevData.filename,
    category: prevData.category,
    collection_name: prevData.collection_name,
    text: cleanText,
    text_length: cleanText.length
  }
};

// Dividir texto en chunks - LIMITADO A ~6000 TOKENS (aprox 24000 caracteres)
const text = $input.first().json.text || '';
const companySlug = $input.first().json.company_slug;
const filename = $input.first().json.filename;
const category = $input.first().json.category;
const collectionName = $input.first().json.collection_name;

// ~4 caracteres = 1 token aprox. Limite 6000 tokens = 24000 chars
// Usamos 20000 para tener margen de seguridad
const maxCharsPerChunk = 20000;
const chunkOverlap = 500;
const chunks = [];

// Si el texto es corto, no dividir
if (text.length <= maxCharsPerChunk) {
  chunks.push(text);
} else {
  // Dividir por párrafos primero
  const paragraphs = text.split(/\n\n+/);
  let currentChunk = '';

  for (const para of paragraphs) {
    // Si agregar este párrafo excede el límite
    if (currentChunk.length + para.length > maxCharsPerChunk) {
      // Guardar chunk actual si tiene contenido
      if (currentChunk.trim()) {
        chunks.push(currentChunk.trim());
      }

      // Si el párrafo solo es muy largo, dividirlo por oraciones
      if (para.length > maxCharsPerChunk) {
        const sentences = para.split(/(?<=[.!?])\s+/);
        currentChunk = '';
        for (const sentence of sentences) {
          if (currentChunk.length + sentence.length > maxCharsPerChunk) {
            if (currentChunk.trim()) chunks.push(currentChunk.trim());
            // Si una sola oración es muy larga, dividir por caracteres
            if (sentence.length > maxCharsPerChunk) {
              for (let i = 0; i < sentence.length; i += maxCharsPerChunk - chunkOverlap) {
                chunks.push(sentence.substring(i, i + maxCharsPerChunk));
              }
              currentChunk = '';
            } else {
              currentChunk = sentence;
            }
          } else {
            currentChunk += (currentChunk ? ' ' : '') + sentence;
          }
        }
      } else {
        currentChunk = para;
      }
    } else {
      currentChunk += (currentChunk ? '\n\n' : '') + para;
    }
  }

  // No olvidar el último chunk
  if (currentChunk.trim()) {
    chunks.push(currentChunk.trim());
  }
}

// Retornar chunks como items separados
return chunks.map((chunk, index) => ({
  json: {
    text: chunk,
    chunk_index: index,
    total_chunks: chunks.length,
    company_slug: companySlug,
    filename: filename,
    category: category,
    collection_name: collectionName
  }
}));

const item = $input.first();
const embedding = item.json.data[0].embedding;
const prevData = $('Split into Chunks').item.json;

return {
  json: {
    id: `${prevData.filename}-${prevData.chunk_index}-${Date.now()}`,
    vector: embedding,
    payload: {
      text: prevData.text,
      filename: prevData.filename,
      category: prevData.category,
      company_slug: prevData.company_slug,
      chunk_index: prevData.chunk_index
    },
    collection_name: prevData.collection_name
  }
};

